          + "&subNodeId=" + new DES().encryptWeb(""+ lastSubRootNodeId)
          + "&receiver=" + new DES().encryptWeb(receiver)
          + "' style='width:1px;height:1px;'/>";
  processedContent += imgStr;

  //User name display in email
  String userName=user.getUserName(apname);
  if("tickets".equals(apname)){//special processing for Ragic
    String[] sec=userName.split(" ");
    userName="Ragic - "+sec[0];
  }

  Mail2 mail2=new Mail2();
  mail2.setIfIgnoreBounceList(true);
  mail2.setAsReply(messageId, reference);
  mail2.setApname(apname);
  mail2.compose(toString,ccString,replyTo,userName,subject,processedContent);
  mail2.setAttachmentMap(map);
  mail2.send();

  //backup copy to sophia
