//  mailer.sendMailAsync("sophia@ragic.com", null, subject, "To: "+toString+"<br>CC: "+ccString+"<br>"+processedContent, replyTo, user.getUserName(apname), true, map);


  //update record
  aq.setUpdateMode();
  APIEntry ae=aq.getAPIEntry(nodeId);
  SimpleDateFormat sdf=new SimpleDateFormat("yyyy/MM/dd HH:mm:ss");
  CellInfo lastUpdateDateField=form.getFieldByAttribute("email_updateDate", null);
  CellInfo lastUpdateEmailField=form.getFieldByAttribute("email_updateEmail", null);
  CellInfo needActionField=form.getFieldByAttribute("email_needAction",null);
  if(lastUpdateDateField!=null) ae.setFieldValue(lastUpdateDateField.getDomainId(),sdf.format(new Date()));//last update
  if(lastUpdateEmailField!=null) ae.setFieldValue(lastUpdateEmailField.getDomainId(), user.getUserId());//last update user
  if(needActionField!=null) ae.setFieldValue(needActionField.getDomainId(),needAction!=null?needAction:"N");//need action = y
  ae.setSendNotification(false);//sent below
  ae.setAddUserAsNotifyUser(true); // [issue#12179]
  ae.save(user,bundle);

  //send out notification
  MailSummary summary=new MailSummary(from.getAddress(),from.getPersonal(),apname,path,sheetIndex,form.getRootDomainId(),nodeId,subject,processedContent);
  summary.setIfReply(true);
  Notification.createNotificationFromSummary(summary, bundle);

